/**
 * Generated by `createservice acquiring.AllCardBindingsService`
 */

const { getLogger } = require('@open-condo/keystone/logging')
const { GQLCustomSchema, find } = require('@open-condo/keystone/schema')

const access = require('@condo/domains/acquiring/access/AllCardBindingsService')
const { ACQUIRING_INTEGRATION_ONLINE_PROCESSING_TYPE } = require('@condo/domains/acquiring/constants/integration')
const { getUserCards } = require('@condo/domains/acquiring/utils/serverSchema/OnlineInteraction')

const logger = getLogger()

const AllCardBindingsService = new GQLCustomSchema('AllCardBindingsService', {
    types: [
        {
            access: true,
            type: `
                input AllCardBindingsInput {
                    user: UserWhereUniqueInput!
                }
            `,
        },
        {
            access: true,
            type: `
                type CardToken {
                    id: String!
                    providers: [String!]!
                    cardNumber: String!
                    paymentSystem: String!
                    expiration: String!
                    bankName: String
                    bankCountryCode: String
                    createdAt: String!
                }
            `,
        },
        {
            access: true,
            type: `
                type AllCardBindingsOutput {
                    cardTokens: [CardToken!]!
                }
            `,
        },
    ],

    queries: [
        {
            access: access.canAllCardBindings,
            schema: 'allCardBindings(data: AllCardBindingsInput!): AllCardBindingsOutput!',
            resolver: async (parent, args) => {
                const {
                    data: {
                        user: { id: userId },
                    },
                } = args

                const acquiringIntegrations = await find('AcquiringIntegration', {
                    type: ACQUIRING_INTEGRATION_ONLINE_PROCESSING_TYPE,
                    getUserCardsUrl_not: null,
                    deleteUserCardUrl_not: null,
                    deletedAt: null,
                })
                
                const results = await Promise.allSettled(
                    acquiringIntegrations.map(integration =>
                        getUserCards(
                            integration.getUserCardsUrl,
                            userId,
                            integration.name,
                            integration.id,
                        )
                    )
                )

                const cardTokens = []

                for (const result of results) {
                    if (result.status === 'fulfilled') {
                        cardTokens.push(...result.value)
                    } else {
                        logger.error({
                            msg: 'Failed to fetch card bindings',
                            err: result.reason,
                        })
                    }
                }

                const deduplicated = new Map()

                for (const card of cardTokens) {
                    const key = [
                        card.id,
                        card.cardNumber,
                        card.paymentSystem,
                        card.expiration,
                    ].join(':')

                    const existing = deduplicated.get(key)

                    if (!existing) {
                        deduplicated.set(key, {
                            ...card,
                            providers: [card.provider],
                        })
                    } else {
                        if (!existing.providers.includes(card.provider)) {
                            existing.providers.push(card.provider)
                        }

                        existing.bankName ||= card.bankName
                        existing.bankCountryCode ||= card.bankCountryCode
                    }
                }

                const uniqueCardTokens = [...deduplicated.values()]

                return {
                    cardTokens: uniqueCardTokens,
                }
            },
        },
    ],
})

module.exports = {
    AllCardBindingsService,
}